const data = msg.payload;
const parts = msg.topic.split('/');
const bikeId = parts[1];

// Authorized parking zones in Genoa (polygons as [lat, lng] arrays)
const ZONES = [
    { name: 'Porto Antico', center: [44.4095, 8.9290], radius: 300 },
    { name: 'Piazza De Ferrari', center: [44.4072, 8.9345], radius: 200 },
    { name: 'Stazione Brignole', center: [44.4153, 8.9425], radius: 250 },
    { name: 'Stazione Principe', center: [44.4103, 8.9213], radius: 250 }
];

function distanceMeters(lat1, lng1, lat2, lng2) {
    const R = 6371000;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLng = (lng2 - lng1) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLng/2) * Math.sin(dLng/2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

// Only check if the bike is nearly stationary
if (data.speed >= 1) return null;

const insideZone = ZONES.some(zone => {
    const dist = distanceMeters(data.lat, data.lng, zone.center[0], zone.center[1]);
    return dist <= zone.radius;
});

if (!insideZone) {
    msg.payload = [{
        measurement: 'alerts',
        tags: {
            bike_id: bikeId,
            type: 'parking_violation',
            severity: 'medium'
        },
        fields: {
            message: 'Bike parked outside authorized zone at ' + data.lat.toFixed(5) + ', ' + data.lng.toFixed(5),
            lat: data.lat,
            lng: data.lng,
            acknowledged: false
        }
    }];
    return msg;
}

return null;

